const BlogEngineMini = () => {
  const STORAGE_KEY = 'titan_blog_posts';
  const [posts, setPosts] = React.useState([]);
  const [view, setView] = React.useState('list');
  const [activeTag, setActiveTag] = React.useState('All');
  const [form, setForm] = React.useState({ title: '', body: '', tags: '' });
  const [editingId, setEditingId] = React.useState(null);

  React.useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) setPosts(JSON.parse(raw));
      else {
        const demo = [
          { id: 1, title: 'Welcome to Titan Blog', body: 'This is a **markdown** blog engine.\n\n- Edit posts\n- Filter by tags\n- Persisted in localStorage', tags: ['intro', 'demo'], date: '2025-04-20' },
          { id: 2, title: 'Building with React', body: 'React makes UI development *declarative* and composable.', tags: ['react', 'dev'], date: '2025-04-22' }
        ];
        setPosts(demo);
      }
    } catch (e) {
      setPosts([]);
    }
  }, []);

  React.useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(posts));
  }, [posts]);

  const allTags = ['All', ...Array.from(new Set(posts.flatMap(p => p.tags)))];

  const filtered = activeTag === 'All' ? posts : posts.filter(p => p.tags.includes(activeTag));

  const parseMarkdown = (text) => {
    let html = text
      .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.+?)\*/g, '<em>$1</em>')
      .replace(/^- (.+)$/gm, '<li>$1</li>')
      .replace(/\n/g, '<br/>');
    return html;
  };

  const handleSave = () => {
    if (!form.title.trim() || !form.body.trim()) return;
    const tagList = form.tags.split(',').map(t => t.trim()).filter(Boolean);
    if (editingId !== null) {
      setPosts(prev => prev.map(p => p.id === editingId ? { ...p, title: form.title, body: form.body, tags: tagList } : p));
    } else {
      setPosts(prev => [{ id: Date.now(), title: form.title, body: form.body, tags: tagList, date: new Date().toISOString().slice(0, 10) }, ...prev]);
    }
    setForm({ title: '', body: '', tags: '' });
    setEditingId(null);
    setView('list');
  };

  const handleEdit = (post) => {
    setForm({ title: post.title, body: post.body, tags: post.tags.join(', ') });
    setEditingId(post.id);
    setView('editor');
  };

  const handleDelete = (id) => {
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  const styles = {
    container: {
      fontFamily: 'system-ui, -apple-system, sans-serif',
      padding: 24,
      background: '#f8fafc',
      minHeight: '100%',
      color: '#1e293b'
    },
    header: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: 16
    },
    title: {
      fontSize: 20,
      fontWeight: 700
    },
    btn: {
      padding: '8px 16px',
      borderRadius: 8,
      border: 'none',
      background: '#2563eb',
      color: '#fff',
      fontWeight: 600,
      cursor: 'pointer',
      fontSize: 14
    },
    btnGhost: {
      padding: '8px 16px',
      borderRadius: 8,
      border: '1px solid #cbd5e1',
      background: '#fff',
      color: '#475569',
      fontWeight: 600,
      cursor: 'pointer',
      fontSize: 14
    },
    btnDanger: {
      padding: '6px 12px',
      borderRadius: 6,
      border: 'none',
      background: '#ef4444',
      color: '#fff',
      fontWeight: 600,
      cursor: 'pointer',
      fontSize: 12
    },
    btnSmall: {
      padding: '6px 12px',
      borderRadius: 6,
      border: 'none',
      background: '#2563eb',
      color: '#fff',
      fontWeight: 600,
      cursor: 'pointer',
      fontSize: 12
    },
    tagRow: {
      display: 'flex',
      gap: 8,
      flexWrap: 'wrap',
      marginBottom: 16
    },
    tag: (active) => ({
      padding: '5px 12px',
      borderRadius: 999,
      fontSize: 12,
      fontWeight: 600,
      cursor: 'pointer',
      border: 'none',
      background: active ? '#2563eb' : '#e2e8f0',
      color: active ? '#fff' : '#475569'
    }),
    card: {
      background: '#fff',
      borderRadius: 12,
      padding: 20,
      marginBottom: 14,
      boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
      border: '1px solid #e2e8f0'
    },
    postTitle: {
      fontSize: 16,
      fontWeight: 700,
      marginBottom: 6
    },
    postMeta: {
      fontSize: 12,
      color: '#94a3b8',
      marginBottom: 10
    },
    postBody: {
      fontSize: 14,
      lineHeight: 1.6,
      color: '#334155'
    },
    postTags: {
      display: 'flex',
      gap: 6,
      marginTop: 12
    },
    postTag: {
      fontSize: 11,
      fontWeight: 600,
      padding: '3px 10px',
      borderRadius: 999,
      background: '#dbeafe',
      color: '#1d4ed8'
    },
    actions: {
      display: 'flex',
      gap: 8,
      marginTop: 12
    },
    input: {
      width: '100%',
      padding: '10px 12px',
      borderRadius: 8,
      border: '1px solid #cbd5e1',
      fontSize: 14,
      outline: 'none',
      marginBottom: 12,
      boxSizing: 'border-box'
    },
    textarea: {
      width: '100%',
      padding: '10px 12px',
      borderRadius: 8,
      border: '1px solid #cbd5e1',
      fontSize: 14,
      outline: 'none',
      minHeight: 140,
      resize: 'vertical',
      marginBottom: 12,
      boxSizing: 'border-box',
      fontFamily: 'inherit'
    },
    previewBox: {
      background: '#f8fafc',
      borderRadius: 8,
      padding: 16,
      border: '1px dashed #cbd5e1',
      marginBottom: 12,
      fontSize: 14,
      lineHeight: 1.6
    },
    label: {
      fontSize: 12,
      fontWeight: 600,
      color: '#475569',
      marginBottom: 6,
      display: 'block'
    }
  };

  if (view === 'editor') {
    return (
      <div style={styles.container}>
        <div style={styles.header}>
          <div style={styles.title}>{editingId !== null ? 'Edit Post' : 'New Post'}</div>
          <button style={styles.btnGhost} onClick={() => { setView('list'); setEditingId(null); setForm({ title: '', body: '', tags: '' }); }}>Back</button>
        </div>
        <div style={styles.card}>
          <label style={styles.label}>Title</label>
          <input
            style={styles.input}
            placeholder="Post title"
            value={form.title}
            onChange={e => setForm({ ...form, title: e.target.value })}
          />
          <label style={styles.label}>Body (markdown supported)</label>
          <textarea
            style={styles.textarea}
            placeholder="Write your post..."
            value={form.body}
            onChange={e => setForm({ ...form, body: e.target.value })}
          />
          <label style={styles.label}>Tags (comma separated)</label>
          <input
            style={styles.input}
            placeholder="tech, tutorial"
            value={form.tags}
            onChange={e => setForm({ ...form, tags: e.target.value })}
          />
          <label style={styles.label}>Preview</label>
          <div style={styles.previewBox} dangerouslySetInnerHTML={{ __html: parseMarkdown(form.body || '(empty)') }} />
          <div style={{ display: 'flex', gap: 10 }}>
            <button style={styles.btn} onClick={handleSave}>Save Post</button>
            <button style={styles.btnGhost} onClick={() => { setForm({ title: '', body: '', tags: '' }); setEditingId(null); setView('list'); }}>Cancel</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div style={styles.title}>📖 Mini Blog</div>
        <button style={styles.btn} onClick={() => setView('editor')}>+ New Post</button>
      </div>
      <div style={styles.tagRow}>
        {allTags.map(tag => (
          <button key={tag} style={styles.tag(activeTag === tag)} onClick={() => setActiveTag(tag)}>
            {tag}
          </button>
        ))}
      </div>
      {filtered.length === 0 && <div style={{ color: '#94a3b8', fontSize: 14 }}>No posts found.</div>}
      {filtered.map(post => (
        <div key={post.id} style={styles.card}>
          <div style={styles.postTitle}>{post.title}</div>
          <div style={styles.postMeta}>{post.date}</div>
          <div style={styles.postBody} dangerouslySetInnerHTML={{ __html: parseMarkdown(post.body) }} />
          <div style={styles.postTags}>
            {post.tags.map(t => (
              <span key={t} style={styles.postTag}>{t}</span>
            ))}
          </div>
          <div style={styles.actions}>
            <button style={styles.btnSmall} onClick={() => handleEdit(post)}>Edit</button>
            <button style={styles.btnDanger} onClick={() => handleDelete(post.id)}>Delete</button>
          </div>
        </div>
      ))}
    </div>
  );
};
render(<BlogEngineMini/>);
